import{_ as e,o as a,c as r,ag as s}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Data & Provenance","description":"","frontmatter":{},"headers":[],"relativePath":"guide/data-provenance.md","filePath":"guide/data-provenance.md"}'),n={name:"guide/data-provenance.md"};function d(o,t,i,l,c,h){return a(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="data-provenance" tabindex="-1">Data &amp; Provenance <a class="header-anchor" href="#data-provenance" aria-label="Permalink to &quot;Data &amp; Provenance&quot;">​</a></h1><h2 id="provenance-model" tabindex="-1">Provenance Model <a class="header-anchor" href="#provenance-model" aria-label="Permalink to &quot;Provenance Model&quot;">​</a></h2><p>Every numeric value in the terminal carries provenance metadata:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes tokyo-night tokyo-night vp-code" tabindex="0"><code><span class="line"><span>Value  →  Field ID  →  Source  →  As-Of timestamp  →  Freshness</span></span></code></pre></div><p><strong>Field lineage</strong> shows:</p><ol><li><strong>Source</strong> — where the raw value came from (SIM feed, LIVE endpoint)</li><li><strong>Transforms</strong> — normalization and guard steps applied</li><li><strong>Displayed</strong> — the final formatted value shown in the UI</li></ol><h2 id="sim-vs-live-vs-stale" tabindex="-1">SIM vs LIVE vs STALE <a class="header-anchor" href="#sim-vs-live-vs-stale" aria-label="Permalink to &quot;SIM vs LIVE vs STALE&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Badge</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>SIM</strong></td><td>Simulated data generated by MarketMind&#39;s built-in simulator. Realistic ranges and patterns but not real market data.</td></tr><tr><td><strong>LIVE</strong></td><td>Real-time streaming value (when High Density Live Mode is enabled). Refreshes every tick.</td></tr><tr><td><strong>STALE</strong></td><td>Value&#39;s age exceeds the expected refresh cadence for that field type (e.g. a tick-frequency field last updated &gt;60 seconds ago).</td></tr><tr><td><strong>CALC</strong></td><td>Derived by calculation from other fields. Not directly sourced.</td></tr></tbody></table><h2 id="freshness-thresholds-by-cadence" tabindex="-1">Freshness Thresholds by Cadence <a class="header-anchor" href="#freshness-thresholds-by-cadence" aria-label="Permalink to &quot;Freshness Thresholds by Cadence&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Cadence</th><th>Stale after</th></tr></thead><tbody><tr><td>Tick</td><td>60 seconds</td></tr><tr><td>Daily</td><td>36 hours</td></tr><tr><td>Monthly</td><td>45 days</td></tr><tr><td>Quarterly</td><td>120 days</td></tr><tr><td>Static</td><td>10 years</td></tr></tbody></table><h2 id="accessing-lineage" tabindex="-1">Accessing Lineage <a class="header-anchor" href="#accessing-lineage" aria-label="Permalink to &quot;Accessing Lineage&quot;">​</a></h2><ol><li><strong>Click any numeric value</strong> in DES, WEI, HP → opens LINE viewer for that field</li><li><strong>Alt+Click</strong> → Inspector shows field provenance in FIELDS section</li><li><strong>FLD GO</strong> → search field catalog, find field, click &quot;Lineage&quot; → LINE</li><li><strong>LINE &lt;field_id&gt; GO</strong> → direct lineage for a specific field</li></ol><h2 id="field-catalog-fld" tabindex="-1">Field Catalog (FLD) <a class="header-anchor" href="#field-catalog-fld" aria-label="Permalink to &quot;Field Catalog (FLD)&quot;">​</a></h2><p>The Field Catalog lists all available data fields:</p><ul><li><strong>id</strong> — unique field identifier (e.g. <code>PX_LAST</code>, <code>PE_RATIO</code>)</li><li><strong>label</strong> — human-readable name</li><li><strong>definition</strong> — what the field measures</li><li><strong>unit</strong> — currency, percentage, ratio, etc.</li><li><strong>type</strong> — scalar (single value) or series (time series)</li><li><strong>cadence</strong> — how often it updates</li><li><strong>chartable</strong> — whether GP/HP can plot it</li><li><strong>availability</strong> — which asset classes support it</li></ul><h2 id="error-states" tabindex="-1">Error States <a class="header-anchor" href="#error-states" aria-label="Permalink to &quot;Error States&quot;">​</a></h2><table tabindex="0"><thead><tr><th>State</th><th>Cause</th><th>Resolution</th></tr></thead><tbody><tr><td><strong>STALE badge</strong></td><td>Value not refreshed within cadence</td><td>Check STAT for feed health; reload panel</td></tr><tr><td><strong>--</strong> value</td><td>Field not available for this security</td><td>Try a different security or asset class</td></tr><tr><td><strong>ERR row</strong></td><td>Data error logged</td><td>Check ERR console for details</td></tr><tr><td><strong>Policy block</strong></td><td>Entitlement restriction</td><td>Check ENT/COMP/POL</td></tr></tbody></table>',17)])])}const p=e(n,[["render",d]]);export{u as __pageData,p as default};
